module RefModule(
    input clk,
    input reset,
    output reg [3:0] count,
    output reg overflow
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            count <= 4'b0000;
            overflow <= 1'b0;
        end
        else begin
            if (count == 4'b1111) begin
                count <= 4'b0000;
                overflow <= 1'b1;
            end
            else begin
                count <= count + 1;
                overflow <= 1'b0;
            end
        end
    end

endmodule
